javascript:(function(){if(window.__hz_ai_loaded){console.log('[AI Signal] already loaded');return;}window.__hz_ai_loaded=true;const script=document.createElement('script');script.src='https://raw.githubusercontent.com/RishvanthAmsaraj/Home-Page-Extension/main/aiscan/score.js';document.head.appendChild(script);script.onload=function(){const sc=window.AIScore;const sel={result:"div.g, div[jscontroller][data-hveid] div.g, [data-snf] .g",anchor:"a[href]:not([role='button'])",title:"h3",snippet:".VwiC3b, .yXK7lf, [data-content-feature], .st",url:"cite, .tjvcx, .dyjrff"};function eh(h){try{const u=new URL(h);return u.hostname.replace(/^www\./,'')}catch(e){return''}}function ex(card){const as=card.querySelectorAll(sel.anchor);let url='',titleEl=null;for(const a of as){const href=a.getAttribute('href');if(href&&/^https?:\/\//i.test(href)){url=href;titleEl=a;break}}if(!url)return null;const title=(card.querySelector(sel.title)||titleEl||{}).textContent?.trim()||'';const snippet=(card.querySelector(sel.snippet)||{}).textContent?.trim()||'';if(!title&&!snippet)return null;return{url,hostname:eh(url),title,snippet}}function band(p){return p<35?'low':p<65?'med':'high'}function bl(b){return b==='low'?'Human-like':b==='med'?'Mixed':'Likely AI'}function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}const style=document.createElement('style');style.textContent='.hz-ai-border{position:relative!important}.hz-ai-border::before{content:"";position:absolute;left:0;top:4px;bottom:4px;width:4px;border-radius:0 2px 2px 0;pointer-events:none;z-index:1}.hz-ai-low::before{background:#22c55e}.hz-ai-med::before{background:#f59e0b}.hz-ai-high::before{background:#ef4444}.hz-ai-badge{display:inline-flex;align-items:center;gap:4px;font-family:system-ui,sans-serif;font-size:11px;font-weight:500;padding:2px 8px;border-radius:999px;margin-left:6px;cursor:help;user-select:none}.hz-ai-badge[data-band="low"]{background:#dcfce7;color:#166534}.hz-ai-badge[data-band="med"]{background:#fef3c7;color:#92400e}.hz-ai-badge[data-band="high"]{background:#fee2e2;color:#991b1b}.hz-ai-dot{width:6px;height:6px;border-radius:50%}.hz-ai-badge[data-band="low"] .hz-ai-dot{background:#22c55e}.hz-ai-badge[data-band="med"] .hz-ai-dot{background:#f59e0b}.hz-ai-badge[data-band="high"] .hz-ai-dot{background:#ef4444}.hz-ai-dismiss{display:inline-flex;align-items:center;justify-content:center;width:14px;height:14px;margin-left:2px;padding:0;border:none;background:transparent;color:inherit;opacity:0.5;cursor:pointer;font-size:10px;border-radius:2px}.hz-ai-dismiss:hover{opacity:1;background:rgba(0,0,0,0.08)}.hz-ai-tooltip{position:absolute;left:12px;top:0;z-index:2147483647;background:rgba(15,15,15,0.95);color:#f0f0f0;padding:10px 14px;border-radius:10px;font-family:system-ui,sans-serif;font-size:12px;line-height:1.6;max-width:340px;box-shadow:0 8px 32px rgba(0,0,0,0.35);backdrop-filter:blur(12px);pointer-events:none;opacity:0;transform:translateY(4px);transition:opacity .15s,transform .15s;white-space:normal}.hz-ai-border:hover .hz-ai-tooltip{opacity:1;transform:translateY(0);pointer-events:auto}.hz-ai-tooltip strong{display:block;font-size:13px;margin-bottom:4px}.hz-ai-tooltip .hz-reasons{opacity:0.75;margin:4px 0}.hz-ai-tooltip .hz-foot{opacity:0.5;font-size:11px;margin-top:6px;padding-top:6px;border-top:1px solid rgba(255,255,255,0.1)}.hz-ai-collapsed{opacity:0.35;filter:grayscale(0.6);transition:opacity .2s,filter .2s}.hz-ai-collapsed:hover{opacity:1;filter:none}';document.head.appendChild(style);const cards=document.querySelectorAll(sel.result);console.log('[AI Signal] scanning',cards.length,'results');let scored=0;cards.forEach(card=>{const d=ex(card);if(!d)return;const text=[d.title,d.snippet].filter(Boolean).join(' — ');const score=sc.score(text,{url:d.url});const b=band(score.overall);card.classList.add('hz-ai-border','hz-ai-'+b);const badge=document.createElement('span');badge.className='hz-ai-badge';badge.dataset.band=b;badge.innerHTML='<span class="hz-ai-dot"></span><span>AI: '+score.overall+'%</span><span>'+bl(b)+'</span><button class="hz-ai-dismiss">✕</button>';const titleEl=card.querySelector('h3');if(titleEl)titleEl.appendChild(badge);else card.insertBefore(badge,card.firstChild);const tip=document.createElement('div');tip.className='hz-ai-tooltip';tip.innerHTML='<strong>AI Signal: '+score.overall+'% · '+bl(b)+'</strong><div class="hz-reasons">'+esc(score.reasons.join(' · ')||'no strong signals')+'</div><div class="hz-foot">Heuristic estimate — not definitive</div>';card.appendChild(tip);badge.querySelector('.hz-ai-dismiss').addEventListener('click',e=>{e.preventDefault();e.stopPropagation();badge.remove();tip.remove();card.classList.remove('hz-ai-border','hz-ai-low','hz-ai-med','hz-ai-high');});scored++;console.log('[AI Signal]',d.hostname,score.overall+'%',bl(b));});alert('AI Signal: scored '+scored+'/'+cards.length+' results. Look for colored borders and hover for details.');};})();